  1	import React, { FC } from 'react';
  2	import { Trans } from 'react-i18next';
  3	
  4	import { V1alpha1MigrationPolicy } from '@kubevirt-ui/kubevirt-api/kubevirt';
  5	import { useModal } from '@kubevirt-utils/components/ModalProvider/ModalProvider';
  6	import VirtualMachineDescriptionItem from '@kubevirt-utils/components/VirtualMachineDescriptionItem/VirtualMachineDescriptionItem';
  7	import { documentationURL } from '@kubevirt-utils/constants/documentation';
  8	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
  9	import { NO_DATA_DASH } from '@kubevirt-utils/resources/vm/utils/constants';
 10	import {
 11	  Button,
 12	  ButtonVariant,
 13	  DescriptionList,
 14	  DescriptionListDescription,
 15	  DescriptionListTerm,
 16	  DescriptionListTermHelpTextButton,
 17	  Flex,
 18	  Grid,
 19	  GridItem,
 20	  Icon,
 21	  Popover,
 22	  Title,
 23	} from '@patternfly/react-core';
 24	import { LinkIcon, PencilAltIcon } from '@patternfly/react-icons';
 25	
 26	import MigrationPolicyEditModal from '../../../../../components/MigrationPolicyEditModal/MigrationPolicyEditModal';
 27	import { migrationPolicySpecKeys } from '../../../../../utils/constants';
 28	import {
 29	  getBandwidthPerMigrationText,
 30	  getBooleanText,
 31	  getCompletionTimeoutText,
 32	} from '../../../../../utils/utils';
 33	
 34	import MigrationPolicyProjectLabels from './components/MigrationPolicyProjectLabels';
 35	import MigrationPolicyVirtualMachineLabels from './components/MigrationPolicyVirtualMachineLabels';
 36	
 37	import './MigrationPolicyDetailsSection.scss';
 38	
 39	type MigrationPolicyDetailsSectionProps = {
 40	  mp: V1alpha1MigrationPolicy;
 41	  pathname: string;
 42	};
 43	
 44	const MigrationPolicyDetailsSection: FC<MigrationPolicyDetailsSectionProps> = ({
 45	  mp,
 46	  pathname,
 47	}) => {
 48	  const { t } = useKubevirtTranslation();
 49	  const { createModal } = useModal();
 50	  const hasOwnPropertySpec = (key: string) => key in (mp?.spec || {});
 51	
 52	  return (
 53	    <div>
 54	      <a className="link-icon" href={`${pathname}#details`}>
 55	        <Icon size="sm">
 56	          {' '}
 57	          <LinkIcon />
 58	        </Icon>
 59	      </a>
 60	      <Title className="kv-details-section-heading" headingLevel="h2">
 61	        {t('MigrationPolicy details')}
 62	      </Title>
 63	      <Grid hasGutter>
 64	        <GridItem span={5}>
 65	          <DescriptionList className="pf-v6-c-description-list">
 66	            <VirtualMachineDescriptionItem
 67	              bodyContent={t(
 68	                'Name must be unique within a namespace. Is required when creating resources, although some resources may allow a client to request the generation of an appropriate name automatically. Name is primarily intended for creation idempotence and configuration definition. ',
 69	              )}
 70	              breadcrumb="MigrationPolicy.metadata.name"
 71	              descriptionData={mp?.metadata?.name}
 72	              descriptionHeader={t('Name')}
 73	              isPopover
 74	              moreInfoURL={documentationURL.NAME}
 75	            />
 76	            <VirtualMachineDescriptionItem
 77	              descriptionData={mp?.metadata?.annotations?.description}
 78	              descriptionHeader={t('Description')}
 79	            />
 80	            <>
 81	              <DescriptionListTerm>
 82	                <Button
 83	                  onClick={() =>
 84	                    createModal(({ isOpen, onClose }) => (
 85	                      <MigrationPolicyEditModal isOpen={isOpen} mp={mp} onClose={onClose} />
 86	                    ))
 87	                  }
 88	                  isInline
 89	                  variant={ButtonVariant.link}
 90	                >
 91	                  <Flex spaceItems={{ default: 'spaceItemsNone' }}>
 92	                    <Title headingLevel="h2">{t('Configurations')}</Title>
 93	                    <PencilAltIcon className="kv-icon-space-l pf-v6-c-button-icon--plain" />
 94	                  </Flex>
 95	                </Button>
 96	              </DescriptionListTerm>
 97	
 98	              <DescriptionListDescription>
 99	                <DescriptionList className="pf-v6-c-description-list">
100	                  <VirtualMachineDescriptionItem
101	                    bodyContent={t(
102	                      'BandwidthPerMigration limits the amount of network bandwith live migrations are allowed to use. The value is in quantity per second. Defaults to 0 (no limit). ',
103	                    )}
104	                    descriptionData={
105	                      hasOwnPropertySpec(migrationPolicySpecKeys.BANDWIDTH_PER_MIGRATION)
106	                        ? getBandwidthPerMigrationText(mp?.spec?.bandwidthPerMigration)
107	                        : NO_DATA_DASH
108	                    }
109	                    descriptionHeader={t('Bandwidth per migration')}
110	                    isPopover
111	                    moreInfoURL={documentationURL.MIGRATION_CONFIGURATION}
112	                  />
113	                  <VirtualMachineDescriptionItem
114	                    bodyContent={t(
115	                      'AllowAutoConverge allows the platform to compromise performance/availability of VMIs to guarantee successful VMI live migrations. Defaults to false. ',
116	                    )}
117	                    descriptionData={
118	                      hasOwnPropertySpec(migrationPolicySpecKeys.ALLOW_AUTO_CONVERGE)
119	                        ? getBooleanText(mp?.spec?.allowAutoConverge)
120	                        : NO_DATA_DASH
121	                    }
122	                    descriptionHeader={t('Auto converge')}
123	                    isPopover
124	                    moreInfoURL={documentationURL.MIGRATION_CONFIGURATION}
125	                  />
126	                  <VirtualMachineDescriptionItem
127	                    bodyContent={t(
128	                      'AllowPostCopy enables post-copy live migrations. Such migrations allow even the busiest VMIs to successfully live-migrate. However, events like a network failure can cause a VMI crash. If set to true, migrations will still start in pre-copy, but switch to post-copy when CompletionTimeoutPerGiB triggers. Defaults to false. ',
129	                    )}
130	                    descriptionData={
131	                      hasOwnPropertySpec(migrationPolicySpecKeys.ALLOW_POST_COPY)
132	                        ? getBooleanText(mp?.spec?.allowPostCopy)
133	                        : NO_DATA_DASH
134	                    }
135	                    descriptionHeader={t('Post-copy')}
136	                    isPopover
137	                    moreInfoURL={documentationURL.MIGRATION_CONFIGURATION}
138	                  />
139	                  <VirtualMachineDescriptionItem
140	                    bodyContent={t(
141	                      'CompletionTimeoutPerGiB is the maximum number of seconds per GiB a migration is allowed to take. If a live-migration takes longer to migrate than this value multiplied by the size of the VMI, the migration will be cancelled, unless AllowPostCopy is true. Defaults to 800. ',
142	                    )}
143	                    descriptionData={
144	                      hasOwnPropertySpec(migrationPolicySpecKeys.COMPLETION_TIMEOUT_PER_GIB)
145	                        ? getCompletionTimeoutText(mp?.spec?.completionTimeoutPerGiB)
146	                        : NO_DATA_DASH
147	                    }
148	                    descriptionHeader={t('Completion timeout')}
149	                    isPopover
150	                    moreInfoURL={documentationURL.MIGRATION_CONFIGURATION}
151	                  />
152	                </DescriptionList>
153	              </DescriptionListDescription>
154	            </>
155	
156	            <Title headingLevel="h2">
157	              <Popover
158	                bodyContent={
159	                  <>
160	                    <Trans ns="plugin__kubevirt-plugin">
161	                      Map of string keys and values that can be used to organize and categorize
162	                      (scope and select) objects. May match selectors of replication controllers and
163	                      services. More info:
164	                    </Trans>{' '}
165	                    <a href={documentationURL.LABELS}>{documentationURL.LABELS}</a>
166	                  </>
167	                }
168	                headerContent={t('Labels')}
169	              >
170	                <DescriptionListTermHelpTextButton>{t('Labels')}</DescriptionListTermHelpTextButton>
171	              </Popover>
172	            </Title>
173	            <MigrationPolicyProjectLabels mp={mp} />
174	            <MigrationPolicyVirtualMachineLabels mp={mp} />
175	          </DescriptionList>
176	        </GridItem>
177	      </Grid>
178	    </div>
179	  );
180	};
181	
182	export default MigrationPolicyDetailsSection;

